// 用数组作为底层数据结构实现栈
#include <vector>

template<typename E>
class MyArrayStack {
private:
    vector<E> arr;

public:
    // 向栈顶加入元素，时间复杂度 O(1)
    void push(const E& e) {
        arr.push_back(e);
    }

    // 从栈顶弹出元素，时间复杂度 O(1)
    E pop() {
        E topElement = arr.back();
        arr.pop_back();
        return topElement;
    }

    // 查看栈顶元素，时间复杂度 O(1)
    E peek() const {
        return arr.back();
    }

    // 返回栈中的元素个数，时间复杂度 O(1)
    int size() const {
        return arr.size();
    }
};

#include <iostream>
#include <deque>

template <typename E>
class MyArrayQueue {
private:
    CycleArray<E> arr;

public:
    MyArrayQueue() {
        arr = CycleArray<E>();
    }

    void push(E t) {
        arr.addLast(t);
    }

    E pop() {
        return arr.removeFirst();
    }

    E peek() {
        return arr.getFirst();
    }

    int size() {
        return arr.size();
    }
};
